     1→import { createContext, useContext, useState, useEffect, ReactNode } from "react";
     2→import type { WikiArticle } from "../components/WikiCard";
     3→import { Heart } from "lucide-react";
     4→import '../assets/heartAnimation.css';
     5→
     6→interface LikedArticlesContextType {
     7→    likedArticles: WikiArticle[];
     8→    toggleLike: (article: WikiArticle) => void;
     9→    isLiked: (pageid: number) => boolean;
    10→}
    11→
    12→const LikedArticlesContext = createContext<LikedArticlesContextType | undefined>(undefined);
    13→
    14→export function LikedArticlesProvider({ children }: { children: ReactNode }) {
    15→    const [likedArticles, setLikedArticles] = useState<WikiArticle[]>(() => {
    16→        const saved = localStorage.getItem("likedArticles");
    17→        return saved ? JSON.parse(saved) : [];
    18→    });
    19→
    20→    const [showHeart, setShowHeart] = useState(false);
    21→
    22→    useEffect(() => {
    23→        localStorage.setItem("likedArticles", JSON.stringify(likedArticles));
    24→    }, [likedArticles]);
    25→
    26→    const toggleLike = (article: WikiArticle) => {
    27→        setLikedArticles((prev) => {
    28→            const alreadyLiked = prev.some((a) => a.pageid === article.pageid);
    29→            if (alreadyLiked) {
    30→                return prev.filter((a) => a.pageid !== article.pageid);
    31→            } else {
    32→                setShowHeart(true);
    33→                setTimeout(() => setShowHeart(false), 800);
    34→                return [...prev, article];
    35→            }
    36→        });
    37→    };
    38→
    39→    const isLiked = (pageid: number) => {
    40→        return likedArticles.some((article) => article.pageid === pageid);
    41→    };
    42→
    43→    return (
    44→        <LikedArticlesContext.Provider value={{ likedArticles, toggleLike, isLiked }}>
    45→            {children}
    46→            {showHeart && (
    47→                <div className="heart-animation">
    48→                    <Heart size={200} strokeWidth={0} className="fill-white"/>
    49→                </div>
    50→            )}
    51→        </LikedArticlesContext.Provider>
    52→    );
    53→}
    54→
    55→export function useLikedArticles() {
    56→    const context = useContext(LikedArticlesContext);
    57→    if (!context) {
    58→        throw new Error("useLikedArticles must be used within a LikedArticlesProvider");
    59→    }
    60→    return context;
    61→}

